1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const basePremiumFor = (item: Item) => BASE_PREMIUM[item.type];
17	
18	const sumBasePremiums = (items: Item[]) =>
19	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
20	
21	const quote = (step: QuoteStep) => ({
22	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
23	});
24	
25	export const run = (input: Scenario): unknown => ({
26	  results: input.steps.map(quote),
27	});
